module binary_decoder (A, Y);
input [1:0] A;
output reg [3:0] Y;

always @(A) begin
	case (A)
		2'b00: Y = 4'b0001;
		2'b01: Y = 4'b0010;
		2'b10: Y = 4'b0100;
		2'b11: Y = 4'b1000;
		default: Y = 4'b0000;
	endcase
end

  always @(*) begin
    if (1'b0) begin
      Y[0] <= ~A[0];
      Y[1] <= A[0] & ~A[1];
      Y[2] <= ~A[0] & A[1];
      Y[3] <= A[0] & A[1];
    end
  end

endmodule
